// frontend/src/pages/EventDetailPage.js
import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Container, Row, Col, Button, Spinner, Alert, Card } from 'react-bootstrap';
import api from '../services/api';
import '../styles/card.css'; // Import file CSS đã cập nhật

function EventDetailPage() {
  const { id } = useParams(); // Lấy ID sự kiện từ URL
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Lấy thông tin user từ localStorage để kiểm tra quyền admin
  const user = JSON.parse(localStorage.getItem('user') || 'null');
  const isAdmin = user && user.role === 'admin';

  useEffect(() => {
    // Hàm gọi API lấy chi tiết sự kiện
    const fetchEventDetail = async () => {
      try {
        setLoading(true);
        // Sử dụng dấu backtick `` để truyền biến id vào URL
        const response = await api.get(`/events/${id}`);
        setEvent(response.data);
        setError(null);
      } catch (err) {
        console.error('Lỗi khi lấy chi tiết sự kiện:', err);
        setError('Không thể tải thông tin sự kiện. Vui lòng thử lại sau.');
      } finally {
        setLoading(false);
      }
    };

    if (id) {
      fetchEventDetail();
    }
  }, [id]);

  // Hiển thị vòng xoay loading khi đang tải dữ liệu
  if (loading) {
    return (
      <Container className="text-center mt-5">
        <Spinner animation="border" role="status" variant="primary">
          <span className="visually-hidden">Đang tải...</span>
        </Spinner>
      </Container>
    );
  }

  // Hiển thị thông báo lỗi nếu có
  if (error) {
    return (
      <Container className="mt-5">
        <Alert variant="danger">{error}</Alert>
        <Button variant="primary" onClick={() => navigate('/home')}>
          Quay lại trang chủ
        </Button>
      </Container>
    );
  }

  // Hiển thị thông báo nếu không tìm thấy sự kiện
  if (!event) {
    return (
      <Container className="mt-5 text-center">
        <h3>Không tìm thấy sự kiện.</h3>
        <Button variant="primary" onClick={() => navigate('/home')} className="mt-3">
          Quay lại trang chủ
        </Button>
      </Container>
    );
  }

  // Định dạng ngày giờ hiển thị
  const eventDate = new Date(event.event_date);
  const formattedDate = eventDate.toLocaleDateString('vi-VN', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });
  const formattedTime = eventDate.toLocaleTimeString('vi-VN', {
    hour: '2-digit',
    minute: '2-digit',
  });

  // GIAO DIỆN CHÍNH CỦA TRANG CHI TIẾT
  return (
    <Container className="py-5">
      <Row className="justify-content-center">
        <Col lg={11}>
          {/* --- Khung Chi tiết Vé (Ticket Detail Card) --- */}
          <Card className="ticket-detail-card shadow border-0 rounded-4">
            
            <Row className="g-0"> {/* g-0 để bỏ khoảng cách giữa các cột của Row này */}
              {/* Cột thông tin vé (Bên trái) */}
              <Col md={7}>
                <div className="ticket-body d-flex flex-column h-100">
                  <div className="flex-grow-1">
                    {/* Tên sự kiện */}
                    <h1 className="ticket-event-title">{event.title}</h1>
                    {/* Tên nghệ sĩ/nhà tổ chức (Giả định lấy dữ liệu từ trường có sẵn) */}
                    <p className="ticket-artist-name">by {event.artist_name || 'Hội đồng sinh viên'}</p>

                    <Row className="mt-4">
                      {/* Cột hiển thị Ngày */}
                      <Col xs={6}>
                        <div className="ticket-label">Ngày</div>
                        <div className="ticket-value">{formattedDate}</div>
                      </Col>
                      {/* Cột hiển thị Giờ */}
                      <Col xs={6}>
                        <div className="ticket-label">Giờ</div>
                        <div className="ticket-value">{formattedTime}</div>
                      </Col>
                    </Row>

                    {/* Hiển thị Giá vé */}
                    <div className="ticket-label mt-2">Giá vé</div>
                    <div className="ticket-value price">
                      {event.price ? `${event.price.toLocaleString('vi-VN')} VND` : 'Miễn phí'}
                    </div>

                    {/* Hiển thị Địa điểm */}
                    <div className="ticket-label mt-2">Địa điểm</div>
                    <div className="ticket-value location">
                      <i className="fa fa-map-marker-alt"></i>
                      {event.location}
                    </div>
                  </div>

                  {/* Nút hành động */}
                  <div className="mt-auto pt-4 d-flex gap-3">
                    <Button variant="primary" size="lg" className="btn-buy-ticket flex-grow-1">
                      Mua vé ngay
                    </Button>
                    {/* Hiển thị nút sửa nếu là Admin */}
                    {isAdmin && (
                      <Button variant="outline-secondary" size="lg" onClick={() => navigate(`/admin/edit-event/${event.id}`)}>
                        <i className="fa fa-edit"></i> Sửa
                      </Button>
                    )}
                  </div>
                </div>
              </Col>

              {/* Cột hiển thị Ảnh Banner (Bên phải) */}
              <Col md={5} className="p-2"> {/* Thêm padding nhỏ cho cột ảnh */}
                <div className="ticket-image-container">
                  <img 
                    src={event.banner_image || 'https://via.placeholder.com/400x500?text=No+Banner'} 
                    alt={event.title} 
                  />
                  <img 
  src={require(`../assets/images/${event.banner_image}`)} 
  alt={event.title} 
/>
                </div>
              </Col>
            </Row>
          </Card>

          {/* --- Phần Mô tả sự kiện (Bên dưới khung vé) --- */}
          <Card className="shadow border-0 rounded-4 mt-4 p-4">
            <h3 className="fw-bold mb-3">Thông tin chi tiết</h3>
            <div className="event-description text-secondary" style={{ lineHeight: '1.7', whiteSpace: 'pre-line' }}>
              {event.description || 'Chưa có mô tả chi tiết cho sự kiện này.'}
            </div>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default EventDetailPage;
